import React, { useState } from "react";

const ProductSuggester = () => {
  const [selectedItems, setSelectedItems] = useState([]);
  const [suggestions, setSuggestions] = useState([]);

  const products = [
    { name: "Laptop", image: "/images/laptop.jpg" },
    { name: "Mouse", image: "/images/mouse.jpg" },
    { name: "Keyboard", image: "/images/keyboard.jpg" },
    { name: "Headphones", image: "/images/headphone.jpg" },
    { name: "Monitor", image: "/images/monitor.jpg" },
  ];

  const toggleSelection = (product) => {
    setSelectedItems((prev) =>
      prev.includes(product)
        ? prev.filter((p) => p !== product)
        : [...prev, product]
    );
  };

  const getSuggestions = async () => {
    try {
      const response = await fetch("http://localhost:3000/api/suggest", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify({ selectedItems }),
      });

      if (!response.ok) {
        throw new Error("Failed to get suggestions");
      }

      const data = await response.json();
      setSuggestions(data);
    } catch (err) {
      console.error("Error fetching suggestions:", err);
    }
  };

  return (
    <div className="p-6 bg-gray-100 min-h-screen">
      <h1 className="text-2xl font-bold text-center mb-6 text-blue-600">
        Chọn sản phẩm để nhận gợi ý
      </h1>

      <div className="flex flex-wrap gap-4 justify-center mb-8">
        {products.map((product) => (
          <div
            key={product.name}
            className={`p-4 border rounded-lg shadow-lg transform transition duration-300 ease-in-out cursor-pointer 
              ${
                selectedItems.includes(product.name)
                  ? "bg-blue-500 text-white border-blue-600 scale-105"
                  : "bg-white text-gray-700 hover:bg-blue-100"
              }`}
            onClick={() => toggleSelection(product.name)}
          >
            <img
              src={product.image} // Đường dẫn ảnh từ thư mục public
              alt={product.name}
              className="w-20 h-20 object-cover mb-2 rounded-md mx-auto"
            />
            <h2 className="text-center">{product.name}</h2>
          </div>
        ))}
      </div>

      <div className="text-center">
        <button
          onClick={getSuggestions}
          className="bg-green-500 text-white px-6 py-3 rounded-full text-lg transition duration-300 ease-in-out hover:bg-green-600"
        >
          Gợi ý sản phẩm
        </button>
      </div>

      <h2 className="mt-8 text-xl font-semibold text-center">
        Gợi ý mua thêm:
      </h2>
      <div className="mt-4">
        {suggestions.length > 0 ? (
          <div className="space-y-4">
            {suggestions.map((sug, index) => (
              <div
                key={index}
                className="p-4 border rounded-lg shadow-md bg-white"
              >
                <h3 className="font-semibold text-lg">
                  {sug.items.join(", ")}{" "}
                  <span className="text-sm text-gray-500">
                    (Support: {(sug.support * 100).toFixed(2)}%)
                  </span>
                </h3>
              </div>
            ))}
          </div>
        ) : (
          <p className="text-center text-gray-500">Không có gợi ý.</p>
        )}
      </div>
    </div>
  );
};

export default ProductSuggester;
